PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "chapters" ("id" integer primary key autoincrement not null, "name" varchar not null, "data" text, "created_at" datetime, "updated_at" datetime, "latitude" numeric, "longitude" numeric, "address" varchar, "phone" varchar, "email" varchar, "description" text);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "chapter_id" integer, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "theme_preference" varchar not null default 'dark');
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "password_reset_requests" ("id" integer primary key autoincrement not null, "user_id" integer, "email" varchar not null, "token" varchar not null, "status" varchar check ("status" in ('pending', 'approved', 'rejected')) not null default 'pending', "approved_at" datetime, "approved_by" integer, "reason" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("approved_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "teams" ("id" integer primary key autoincrement not null, "name" varchar not null, "short" varchar, "chapter_id" integer, "banner" varchar, "has_team_lead" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "profiles" ("id" integer primary key autoincrement not null, "user_id" integer not null, "chapter_id" integer, "first_name" varchar, "last_name" varchar, "gender" varchar, "dob" date, "phone" varchar, "secondary_phone" varchar, "email" varchar, "address" varchar, "city" varchar, "state" varchar, "country" varchar, "marital_status" varchar, "wedding_anniversary" date, "occupation" varchar, "employer" varchar, "education_level" varchar, "baptism_status" varchar, "membership_date" date, "avatar" varchar, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "units" ("id" integer primary key autoincrement not null, "team_id" integer not null, "chapter_id" integer, "name" varchar not null, "short" varchar, "created_at" datetime, "updated_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "team_user" ("id" integer primary key autoincrement not null, "team_id" integer not null, "user_id" integer not null, "chapter_id" integer, "unit_id" integer, "role_in_team" varchar not null default 'member', "created_at" datetime, "updated_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade, foreign key("unit_id") references "units"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "permissions" ("id" integer primary key autoincrement not null, "name" varchar not null, "guard_name" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "roles" ("id" integer primary key autoincrement not null, "name" varchar not null, "guard_name" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "model_has_permissions" ("permission_id" integer not null, "model_type" varchar not null, "model_id" integer not null, foreign key("permission_id") references "permissions"("id") on delete cascade, primary key ("permission_id", "model_id", "model_type"));
CREATE TABLE IF NOT EXISTS "model_has_roles" ("role_id" integer not null, "model_type" varchar not null, "model_id" integer not null, foreign key("role_id") references "roles"("id") on delete cascade, primary key ("role_id", "model_id", "model_type"));
CREATE TABLE IF NOT EXISTS "role_has_permissions" ("permission_id" integer not null, "role_id" integer not null, foreign key("permission_id") references "permissions"("id") on delete cascade, foreign key("role_id") references "roles"("id") on delete cascade, primary key ("permission_id", "role_id"));
CREATE TABLE IF NOT EXISTS "activity_log" ("id" integer primary key autoincrement not null, "log_name" varchar, "description" text not null, "subject_type" varchar, "subject_id" integer, "causer_type" varchar, "causer_id" integer, "properties" text, "created_at" datetime, "updated_at" datetime, "event" varchar, "batch_uuid" varchar);
CREATE TABLE IF NOT EXISTS "team_functions" ("id" integer primary key autoincrement not null, "team_id" integer not null, "function" text not null default '{report:true}', "created_at" datetime, "updated_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "media" ("id" integer primary key autoincrement not null, "model_type" varchar not null, "model_id" integer not null, "uuid" varchar, "collection_name" varchar not null, "name" varchar not null, "file_name" varchar not null, "mime_type" varchar, "disk" varchar not null, "conversions_disk" varchar, "size" integer not null, "manipulations" text not null, "custom_properties" text not null, "generated_conversions" text not null, "responsive_images" text not null, "order_column" integer, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "chapter_settings" ("id" integer primary key autoincrement not null, "chapter_id" integer not null, "name" varchar, "tagline" varchar, "logo" varchar, "banner_image" varchar, "address" varchar, "city" varchar, "state" varchar, "country" varchar, "phone" varchar, "alt_phone" varchar, "email" varchar, "map_location" varchar, "service_times" text, "special_events" text, "social_links" text, "livestream_url" varchar, "giving_url" varchar, "extras" text, "created_at" datetime, "updated_at" datetime, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "global_settings" ("id" integer primary key autoincrement not null, "church_name" varchar, "denomination" varchar, "tagline" varchar, "logo" varchar, "favicon" varchar, "banner_image" varchar, "livestream_url" varchar, "podcast_url" varchar, "giving_url" varchar, "social_links" text, "meta_title" varchar, "meta_description" text, "meta_keywords" text, "extras" text, "created_at" datetime, "updated_at" datetime, "address" varchar, "phone" varchar, "email" varchar);
CREATE TABLE IF NOT EXISTS "services" ("id" integer primary key autoincrement not null, "chapter_id" integer not null, "name" varchar not null, "day_of_week" varchar, "start_time" time, "end_time" time, "is_recurring" tinyint(1) not null default '1', "special_date" date, "location" varchar, "livestream_url" varchar, "message_url" varchar, "description" text, "created_at" datetime, "updated_at" datetime, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "church_reports" ("id" integer primary key autoincrement not null, "report_date" date not null, "title" varchar not null, "description" text, "event_type" varchar, "level" varchar check ("level" in ('team', 'chapter', 'hq')) not null default 'team', "chapter_id" integer, "team_id" integer, "created_by" integer, "created_at" datetime, "updated_at" datetime, foreign key("chapter_id") references "chapters"("id") on delete set null, foreign key("team_id") references "teams"("id") on delete set null, foreign key("created_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "finances" ("id" integer primary key autoincrement not null, "type" varchar not null, "amount" numeric not null, "description" text, "date" date not null, "team_id" integer not null, "user_id" integer not null, "chapter_id" integer not null, "category" varchar, "reference" varchar, "receipt" varchar, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "attendance" ("id" integer primary key autoincrement not null, "event_name" varchar not null, "date" date not null, "attendee_count" integer not null, "notes" text, "team_id" integer not null, "chapter_id" integer not null, "user_id" integer not null, "event_type" varchar, "location" varchar, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "minutes" ("id" integer primary key autoincrement not null, "title" varchar not null, "content" text not null, "meeting_date" date not null, "team_id" integer not null, "user_id" integer not null, "chapter_id" integer not null, "status" varchar not null default 'draft', "attendees" text, "location" varchar, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "appointment_reports" ("id" integer primary key autoincrement not null, "appointment_id" integer not null, "title" varchar not null, "summary" text, "date" date not null, "team_id" integer not null, "chapter_id" integer not null, "user_id" integer not null, "report_file_path" varchar, "status" varchar not null default 'draft', "notes" text, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("appointment_id") references "appointments"("id") on delete cascade, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "finance_reports" ("id" integer primary key autoincrement not null, "finance_id" integer not null, "title" varchar not null, "summary" text, "date" date not null, "team_id" integer not null, "chapter_id" integer not null, "user_id" integer not null, "status" varchar not null default 'draft', "notes" text, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("finance_id") references "finances"("id") on delete cascade, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "attendance_reports" ("id" integer primary key autoincrement not null, "attendance_id" integer not null, "title" varchar not null, "summary" text, "date" date not null, "team_id" integer not null, "chapter_id" integer not null, "user_id" integer not null, "status" varchar not null default 'draft', "notes" text, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("attendance_id") references "attendance"("id") on delete cascade, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "reports" ("id" integer primary key autoincrement not null, "report_date" date not null, "title" varchar not null, "description" text, "event_type" varchar, "report_path" varchar, "report" text, "level" varchar check ("level" in ('team', 'chapter', 'hq')) not null default 'team', "chapter_id" integer, "team_id" integer, "created_by" integer, "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, "status" varchar not null default 'submitted', "report_data" text, foreign key("chapter_id") references "chapters"("id") on delete set null, foreign key("team_id") references "teams"("id") on delete set null, foreign key("created_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "appointment_teams" ("id" integer primary key autoincrement not null, "team_id" integer not null, "chapter_id" integer not null, "free Time" varchar, "free_days" varchar, "created_at" datetime, "updated_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "appointments" ("id" integer primary key autoincrement not null, "username" varchar, "email" varchar, "title" varchar not null, "description" text, "day" date not null, "date" datetime, "start_time" datetime, "end_time" datetime, "team_id" integer not null, "chapter_id" integer, "user_id" integer, "status" varchar check ("status" in ('pending', 'confirmed', 'cancelled')) not null default 'pending', "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "prayer_requests" ("id" integer primary key autoincrement not null, "name" varchar, "email" varchar, "request" text not null, "chapter_id" integer not null, "user_id" integer, "is_addressed" varchar not null default 'pending', "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("chapter_id") references "chapters"("id") on delete set null, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "prayer_request_teams" ("id" integer primary key autoincrement not null, "team_id" integer not null, "chapter_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "believers_academies" ("id" integer primary key autoincrement not null, "chapter_id" integer not null, "status" varchar check ("status" in ('open', 'closed')) not null default 'open', "start_at" date not null, "created_at" datetime, "updated_at" datetime, "certificate_template" varchar, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "academy_clases" ("id" integer primary key autoincrement not null, "name" varchar not null, "date" date not null, "time" varchar not null, "description" text, "academy_id" integer not null, "study_material" text, "tutor" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("academy_id") references "believers_academies"("id") on delete cascade, foreign key("tutor") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "believers_academy_teams" ("id" integer primary key autoincrement not null, "team_id" integer not null, "chapter_id" integer not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "partnerships" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "phone" varchar, "preferred_location" varchar, "partnership_interests" text, "status" varchar check ("status" in ('pending', 'under_review', 'approved', 'rejected', 'active')) not null default 'pending', "notes" text, "organization" varchar, "website" varchar, "partnership_type" varchar check ("partnership_type" in ('financial', 'strategic', 'ministry', 'technology', 'other')), "proposed_amount" numeric, "start_date" date, "end_date" date, "assigned_to" integer, "reviewed_at" datetime, "reviewed_by" integer, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("assigned_to") references "users"("id") on delete set null, foreign key("reviewed_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "partnerships_settings" ("id" integer primary key autoincrement not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "events" ("id" integer primary key autoincrement not null, "chapter_id" integer, "created_by" integer, "title" varchar not null, "slug" varchar, "description" text, "start_at" datetime not null, "end_at" datetime, "timezone" varchar, "location" varchar, "is_online" tinyint(1) not null default '0', "livestream_url" varchar, "banner" varchar, "status" varchar check ("status" in ('draft', 'published', 'cancelled', 'archived')) not null default 'draft', "capacity" integer, "registration_required" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, "form_schema" text, foreign key("chapter_id") references "chapters"("id") on delete set null, foreign key("created_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "event_forms" ("id" integer primary key autoincrement not null, "event_id" integer not null, "chapter_id" integer, "name" varchar not null, "email" varchar, "phone" varchar, "guests" integer not null default '0', "form" text not null, "answers" text, "notes" text, "status" varchar check ("status" in ('pending', 'confirmed', 'cancelled')) not null default 'pending', "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("event_id") references "events"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "event_galleries" ("id" integer primary key autoincrement not null, "event_id" integer not null, "chapter_id" integer, "title" varchar, "file_path" varchar not null, "thumbnail_path" varchar, "mime_type" varchar, "size" integer, "order_column" integer, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("event_id") references "events"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "accounts" ("id" integer primary key autoincrement not null, "account_name" varchar not null, "account_number" varchar not null, "bank_name" varchar not null, "bank_code" varchar, "swift_code" varchar, "iban" varchar, "account_type" varchar check ("account_type" in ('checking', 'savings', 'business', 'ministry', 'donation')) not null default 'ministry', "currency" varchar not null default 'USD', "region" varchar not null, "country" varchar, "description" text, "is_active" tinyint(1) not null default '1', "accepts_online_payments" tinyint(1) not null default '0', "accepts_international" tinyint(1) not null default '0', "supported_payment_methods" text, "minimum_amount" numeric, "maximum_amount" numeric, "special_instructions" text, "contact_person" varchar, "contact_email" varchar, "contact_phone" varchar, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, "chapter_id" integer);
CREATE TABLE IF NOT EXISTS "account_events" ("id" integer primary key autoincrement not null, "account_id" integer not null, "event_id" integer not null, "created_at" datetime, "updated_at" datetime, "registered_at" datetime, "status" varchar check ("status" in ('registered', 'attended', 'cancelled', 'pending')) not null default 'registered', foreign key("account_id") references "accounts"("id") on delete cascade, foreign key("event_id") references "events"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "notifications" ("id" varchar not null, "type" varchar not null, "notifiable_type" varchar not null, "notifiable_id" integer not null, "data" text not null, "read_at" datetime, "created_at" datetime, "updated_at" datetime, primary key ("id"));
CREATE TABLE IF NOT EXISTS "testimonies" ("id" integer primary key autoincrement not null, "name" varchar, "email" varchar not null, "testimony" text not null, "image" varchar, "status" varchar check ("status" in ('pending', 'approved', 'rejected')) not null default 'pending', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "series" ("id" integer primary key autoincrement not null, "title" varchar not null, "description" text, "image" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "sermon_medias" ("id" integer primary key autoincrement not null, "mediable_type" varchar not null, "mediable_id" integer not null, "file_name" varchar not null, "file_path" varchar not null, "mime_type" varchar not null, "file_size" integer not null, "type" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "transports" ("id" integer primary key autoincrement not null, "name" varchar not null, "phone" varchar not null, "pickup_location" text not null, "status" varchar check ("status" in ('pending', 'approved', 'rejected')) not null default 'pending', "notes" text, "processed_at" datetime, "created_at" datetime, "updated_at" datetime, "chapter_id" integer, "pickup_location_id" integer, "pickup_time" time, "user_address" varchar, "user_latitude" numeric, "user_longitude" numeric);
CREATE TABLE IF NOT EXISTS "event_teams" ("id" integer primary key autoincrement not null, "team_id" integer not null, "chapter_id" integer not null, "created_at" datetime, "updated_at" datetime, "event_id" integer, foreign key("event_id") references "events"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "about_us" ("id" integer primary key autoincrement not null, "chapter_id" integer not null, "title" varchar not null, "description" text not null, "mission" text, "vision" text, "core_values" text, "hero_image" varchar, "history_timeline" text, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "church_leaders" ("id" integer primary key autoincrement not null, "chapter_id" integer not null, "name" varchar not null, "position" varchar not null, "bio" text, "photo" varchar, "facebook_url" varchar, "twitter_url" varchar, "instagram_url" varchar, "linkedin_url" varchar, "order_column" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "conclaves" ("id" integer primary key autoincrement not null, "name" varchar not null, "location" varchar not null, "description" text, "address" varchar, "phone" varchar, "email" varchar, "latitude" numeric, "longitude" numeric, "image" varchar, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "cell_leaders" ("id" integer primary key autoincrement not null, "cell_group_id" integer not null, "user_id" integer, "name" varchar not null, "phone" varchar not null, "email" varchar, "bio" text, "photo" varchar, "is_primary" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("cell_group_id") references "cell_groups"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "cell_members" ("id" integer primary key autoincrement not null, "cell_group_id" integer not null, "account_id" integer, "name" varchar not null, "phone" varchar, "email" varchar, "joined_at" date not null, "status" varchar check ("status" in ('active', 'inactive', 'transferred')) not null default 'active', "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("cell_group_id") references "cell_groups"("id") on delete cascade, foreign key("account_id") references "accounts"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "cell_attendance" ("id" integer primary key autoincrement not null, "cell_group_id" integer not null, "cell_member_id" integer not null, "attendance_date" date not null, "present" tinyint(1) not null default '0', "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("cell_group_id") references "cell_groups"("id") on delete cascade, foreign key("cell_member_id") references "cell_members"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "mission_teams" ("id" integer primary key autoincrement not null, "team_id" integer not null, "chapter_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "transport_teams" ("id" integer primary key autoincrement not null, "team_id" integer not null, "chapter_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "announcements" ("id" integer primary key autoincrement not null, "chapter_id" integer not null, "title" varchar not null, "description" varchar, "content" text, "image" varchar, "starts_at" datetime, "expires_at" datetime, "is_active" tinyint(1) not null default '1', "priority" integer not null default '0', "type" varchar check ("type" in ('notice', 'event', 'reminder', 'urgent')) not null default 'notice', "created_at" datetime, "updated_at" datetime, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "cell_groups" ("id" integer primary key autoincrement not null, "chapter_id" integer not null, "name" varchar not null, "description" text, "meeting_day" varchar, "meeting_time" time, "location" varchar, "address" text, "latitude" numeric, "longitude" numeric, "max_members" integer not null default ('15'), "phone" varchar, "image" varchar, "is_active" tinyint(1) not null default ('1'), "created_at" datetime, "updated_at" datetime, "conclave_id" integer, foreign key("chapter_id") references chapters("id") on delete cascade on update no action, foreign key("conclave_id") references "conclaves"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "sermons" ("id" integer primary key autoincrement not null, "title" varchar not null, "description" text, "preached_at" date not null, "image_path" varchar not null, "series_id" integer not null, "created_at" datetime, "updated_at" datetime, "chapter_id" integer, foreign key("series_id") references series("id") on delete cascade on update no action, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "service_times" ("id" integer primary key autoincrement not null, "day" varchar not null, "name" varchar not null, "time" varchar not null, "description" text, "order" integer not null default '0', "active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "about_pages" ("id" integer primary key autoincrement not null, "section_key" varchar not null, "title" varchar not null, "content" text not null, "image" varchar, "is_active" tinyint(1) not null default '1', "order" integer not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "event_registrations" ("id" integer primary key autoincrement not null, "event_id" integer not null, "name" varchar not null, "email" varchar not null, "phone" varchar, "additional_info" text, "registered_at" datetime not null, "created_at" datetime, "updated_at" datetime, foreign key("event_id") references "events"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "auth_page_settings" ("id" integer primary key autoincrement not null, "login_image" varchar, "register_image" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "pickup_locations" ("id" integer primary key autoincrement not null, "name" varchar not null, "description" text, "contact_person" varchar, "contact_phone" varchar, "pickup_time" time not null, "chapter_id" integer not null, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, "address" varchar, "latitude" numeric, "longitude" numeric, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "academy_batches" ("id" integer primary key autoincrement not null, "name" varchar not null, "start_date" date not null, "academy_id" integer not null, "max_students" integer, "created_at" datetime, "updated_at" datetime, "status" varchar check ("status" in ('open', 'closed')) not null default 'open', foreign key("academy_id") references "believers_academies"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "student_classes" ("id" integer primary key autoincrement not null, "user_id" integer not null, "class_completed" text not null, "status" varchar not null default ('started'), "cert" varchar, "created_at" datetime, "updated_at" datetime, "how_did_you_know_about_us" varchar not null, "interest" text, "phone" varchar not null, "academy_id" integer, "certificate_path" varchar, "certificate_requested_at" datetime, "certificate_approved_at" datetime, "certificate_status" varchar not null default ('pending'), "attendance_record" text, "performance_score" numeric not null default ('0'), "notes" text, "last_activity" datetime, "batch_id" integer, foreign key("user_id") references users("id") on delete cascade on update no action, foreign key("academy_id") references believers_academies("id") on delete set null on update no action, foreign key("batch_id") references "academy_batches"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "batch_classes" ("id" integer primary key autoincrement not null, "batch_id" integer not null, "class_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("batch_id") references "academy_batches"("id") on delete cascade, foreign key("class_id") references "academy_clases"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "landing_page_settings" ("id" integer primary key autoincrement not null, "created_at" datetime, "updated_at" datetime, "show_announcements" tinyint(1) not null default ('1'), "show_services" tinyint(1) not null default ('1'), "show_sermons" tinyint(1) not null default ('1'), "max_announcements" integer not null default ('5'), "max_services" integer not null default ('5'), "max_sermons" integer not null default ('3'), "show_testimonies" tinyint(1) not null default ('1'), "max_testimonies" integer not null default ('5'), "hero_image" varchar, "hero_video" varchar, "hero_media_type" varchar not null default ('image'), "selected_chapter_id" integer, "login_image" varchar, "register_image" varchar, "carousel" text, "services" text, "number_of_testimonies" integer not null default ('5'), "hero_section" text, "chapter_id" integer, foreign key("selected_chapter_id") references chapters("id") on delete set null on update no action, foreign key("chapter_id") references "chapters"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "partnership_intents" ("id" integer primary key autoincrement not null, "chapter_id" integer not null, "user_id" integer, "partnership_category_id" integer, "account_id" integer, "event_id" integer, "intent_type" varchar check ("intent_type" in ('general', 'event', 'project')) not null default 'general', "title" varchar not null, "pledge_amount" numeric, "pledge_currency" varchar not null default 'NGN', "pledge_frequency" varchar check ("pledge_frequency" in ('one_time', 'weekly', 'monthly', 'quarterly', 'yearly', 'custom')) not null default 'one_time', "status" varchar check ("status" in ('draft', 'pending', 'reviewing', 'approved', 'declined', 'withdrawn')) not null default 'pending', "notes" text, "admin_notes" text, "pledged_at" datetime, "withdrawn_at" datetime, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("chapter_id") references "chapters"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete set null, foreign key("partnership_category_id") references "partnership_categories"("id") on delete set null, foreign key("account_id") references "accounts"("id") on delete set null, foreign key("event_id") references "events"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "partnership_categories" ("id" integer primary key autoincrement not null, "chapter_id" integer, "name" varchar not null, "slug" varchar not null, "description" text, "is_active" tinyint(1) not null default ('1'), "created_at" datetime, "updated_at" datetime, "account_id" integer, foreign key("chapter_id") references chapters("id") on delete set null on update no action, foreign key("account_id") references "accounts"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "attendance_events" ("id" integer primary key autoincrement not null, "chapter_id" integer not null, "name" varchar not null, "source_type" varchar not null default 'custom', "event_id" integer, "service_id" integer, "location" varchar, "is_active" tinyint(1) not null default '1', "created_by" integer, "created_at" datetime, "updated_at" datetime, foreign key("chapter_id") references "chapters"("id") on delete cascade, foreign key("event_id") references "events"("id") on delete set null, foreign key("service_id") references "services"("id") on delete set null, foreign key("created_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "attendance_sessions" ("id" integer primary key autoincrement not null, "attendance_event_id" integer not null, "date" date not null, "status" varchar not null default 'open', "location" varchar, "notes" text, "opened_by" integer, "closed_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("attendance_event_id") references "attendance_events"("id") on delete cascade, foreign key("opened_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "attendance_checkins" ("id" integer primary key autoincrement not null, "attendance_session_id" integer not null, "user_id" integer, "guest_name" varchar, "guest_email" varchar, "guest_phone" varchar, "source" varchar not null default 'self', "checked_in_at" datetime not null, "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("attendance_session_id") references "attendance_sessions"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete set null);
